#include "behavior_planner/decision/behavior_scorer.hpp"
namespace behavior_planner { BehaviorScore BehaviorScorer::score(const UrbanFeature&f,const HardConstraint&h)const{BehaviorScore s;s.keep=70;s.follow=f.surrounding.has_front_vehicle?65:-1e6;if(f.surrounding.has_front_vehicle){double t=f.surrounding.front_vehicle.ttc;s.keep-=t<3?35:10;s.follow+=t<3?20:5;}bool slow=f.surrounding.has_front_vehicle&&f.surrounding.front_vehicle.speed+1<f.ego.speed;s.left_change=(!h.forbid_left_change&&f.surrounding.left_lane_safe)?(slow?85:45):-1e6;s.right_change=(!h.forbid_right_change&&f.surrounding.right_lane_safe)?(slow?80:40):-1e6;s.stop=h.force_stop?1e5:-1e6;s.emergency_stop=h.emergency_stop?1e6:-1e6;return s;} }
